import type { ToolDefinition } from "../types.js";
import { clampLimit, cursorAndLimitSchema, decodeCursor, idOnlySchema, paginate } from "./_helpers.js";
import { confirmDestructive } from "../elicit.js";
import { McpToolError } from "../errors.js";

const INTERVAL_UNITS = ["day", "week", "month", "quarter", "year"] as const;

type ListResp = { data: unknown[]; meta?: { total?: number; limit?: number; offset?: number } };

// ── Plans ────────────────────────────────────────────────────────────────────

export const list_plans: ToolDefinition = {
  name: "list_plans",
  description:
    "List subscription billing plans (recurring price configurations) for the merchant. Each plan has code, name, billing interval, amount in paisa, and trial days.",
  inputSchema: cursorAndLimitSchema,
  annotations: { readOnlyHint: true, title: "List billing plans" },
  requiredScopes: ["billing:read"],
  async handler(args, ctx) {
    const a = args as { cursor?: string; limit?: number };
    const limit = clampLimit(a.limit);
    const { offset } = decodeCursor(a.cursor);
    const raw = await ctx.api.get<ListResp>("/v1/billing/plans", { query: { limit, offset } });
    return paginate(raw, limit, offset);
  },
};

export const get_plan: ToolDefinition = {
  name: "get_plan",
  description: "Fetch a single billing plan by id.",
  inputSchema: idOnlySchema("plan_id", "Billing plan id (e.g., plan_abc123)."),
  annotations: { readOnlyHint: true, title: "Get billing plan" },
  requiredScopes: ["billing:read"],
  async handler(args, ctx) {
    const { plan_id } = args as { plan_id: string };
    if (!plan_id) throw new Error("plan_id is required");
    return ctx.api.get(`/v1/billing/plans/${encodeURIComponent(plan_id)}`);
  },
};

