import type { ToolDefinition } from "../types.js";
import { clampLimit, cursorAndLimitSchema, decodeCursor, idOnlySchema, paginate } from "./_helpers.js";
import { confirmDestructive } from "../elicit.js";
import { McpToolError } from "../errors.js";

const KNOWN_WEBHOOK_EVENTS = [
  "payment.succeeded",
  "payment.failed",
  "payment.refunded",
  "payment_link.paid",
  "subscription.created",
  "subscription.cancelled",
  "subscription.paused",
  "subscription.resumed",
  "invoice.created",
  "invoice.paid",
  "invoice.overdue",
] as const;

type ListResp = { data: unknown[]; meta?: { total?: number; limit?: number; offset?: number } };

export const list_webhook_endpoints: ToolDefinition = {
  name: "list_webhook_endpoints",
  description:
    "List webhook endpoints registered on the API key's project. Returns each endpoint's id, url, subscribed events, and enabled status. Signing secrets are never returned here — they are shown only at endpoint creation.",
  inputSchema: { type: "object", properties: {}, additionalProperties: false },
  annotations: { readOnlyHint: true, title: "List webhook endpoints" },
  requiredScopes: ["webhooks:read"],
  async handler(_args, ctx) {
    const raw = await ctx.api.get<unknown>("/v1/webhooks");
    return raw;
  },
};

export const create_webhook_endpoint: ToolDefinition = {
  name: "create_webhook_endpoint",
  description:
    "Register a new webhook endpoint. The signing_secret is returned ONCE here and never again — show it to the user immediately so they can store it for HMAC verification. URL must be HTTPS and publicly reachable (private IPs are rejected server-side).",
  inputSchema: {
    type: "object",
    properties: {
      url: {
        type: "string",
        format: "uri",
        description: "Public HTTPS URL where webhook events will POST.",
      },
      events: {
        type: "array",
        items: { type: "string", enum: [...KNOWN_WEBHOOK_EVENTS] },
        minItems: 1,
        description: "Event types to subscribe to.",
      },
    },
    required: ["url", "events"],
    additionalProperties: false,
  },
  annotations: { idempotentHint: false, title: "Create webhook endpoint" },
  requiredScopes: ["webhooks:write"],
  async handler(args, ctx) {
    const a = args as { url: string; events: string[] };
    if (!a.url?.startsWith("https://")) {
      throw new McpToolError("invalid_request", "url must be HTTPS", 400);
    }
    if (!Array.isArray(a.events) || a.events.length === 0) {
      throw new McpToolError("invalid_request", "events must be a non-empty array", 400);
    }
    return ctx.api.post("/v1/webhooks", { body: { url: a.url, events: a.events } });
  },
};

export const update_webhook_endpoint: ToolDefinition = {
  name: "update_webhook_endpoint",
  description: "Update a webhook endpoint's URL or subscribed events.",
  inputSchema: {
    type: "object",
    properties: {
      endpoint_id: { type: "string", description: "Webhook endpoint id (e.g., whe_abc123)." },
      url: { type: "string", format: "uri", description: "New HTTPS URL." },
      events: {
        type: "array",
        items: { type: "string", enum: [...KNOWN_WEBHOOK_EVENTS] },
        description: "Replacement event subscription list.",
      },
    },
    required: ["endpoint_id"],
    additionalProperties: false,
  },
  annotations: { destructiveHint: true, title: "Update webhook endpoint" },
  requiredScopes: ["webhooks:write"],
  async handler(args, ctx) {
    const a = args as { endpoint_id: string; url?: string; events?: string[] };
    if (!a.endpoint_id) throw new Error("endpoint_id is required");
    const body: Record<string, unknown> = {};
    if (a.url !== undefined) body.url = a.url;
    if (a.events !== undefined) body.events = a.events;
    return ctx.api.patch(`/v1/webhooks/${encodeURIComponent(a.endpoint_id)}`, { body });
  },
};

export const delete_webhook_endpoint: ToolDefinition = {
  name: "delete_webhook_endpoint",
  description:
    "Permanently delete a webhook endpoint. The endpoint will stop receiving events immediately. Asks the user to confirm before executing.",
  inputSchema: idOnlySchema("endpoint_id", "Webhook endpoint id (e.g., whe_abc123)."),
  annotations: { destructiveHint: true, title: "Delete webhook endpoint" },
  requiredScopes: ["webhooks:write"],
  async handler(args, ctx) {
    const { endpoint_id } = args as { endpoint_id: string };
    if (!endpoint_id) throw new Error("endpoint_id is required");

    // Hydrate so the confirm modal shows the URL being removed.
    const list = await ctx.api.get<{ data: Array<{ id: string; url: string }> }>("/v1/webhooks");
    const target = list.data?.find((e) => e.id === endpoint_id);

    const ok = await confirmDestructive(ctx.elicit, {
      message: `Permanently delete webhook endpoint ${endpoint_id}?`,
      summary: {
        endpoint_id,
        url: target?.url ?? "(not found — confirm to delete anyway)",
      },
    });
    if (!ok) {
      throw new McpToolError("user_cancelled", "Delete cancelled by user.", 0);
    }
    return ctx.api.delete(`/v1/webhooks/${encodeURIComponent(endpoint_id)}`);
  },
};

export const list_webhook_deliveries: ToolDefinition = {
  name: "list_webhook_deliveries",
  description:
    "List recent delivery attempts for a webhook endpoint. Each delivery has event type, status (pending/delivered/failed), HTTP response code, retry count, and timestamps. Use this to diagnose why a webhook didn't reach the merchant's server.",
  inputSchema: {
    type: "object",
    properties: {
      endpoint_id: {
        type: "string",
        description: "Webhook endpoint id (e.g., whe_abc123).",
      },
      cursor: cursorAndLimitSchema.properties.cursor,
      limit: cursorAndLimitSchema.properties.limit,
    },
    required: ["endpoint_id"],
    additionalProperties: false,
  },
  annotations: { readOnlyHint: true, title: "List webhook deliveries" },
  requiredScopes: ["webhooks:read"],
  async handler(args, ctx) {
    const a = args as { endpoint_id: string; cursor?: string; limit?: number };
    if (!a.endpoint_id) throw new Error("endpoint_id is required");
    const limit = clampLimit(a.limit);
    const { offset } = decodeCursor(a.cursor);
    const raw = await ctx.api.get<ListResp>(
      `/v1/webhooks/${encodeURIComponent(a.endpoint_id)}/deliveries`,
      { query: { limit, offset } },
    );
    return paginate(raw, limit, offset);
  },
};
