import type { ToolDefinition } from "../types.js";
import { clampLimit, cursorAndLimitSchema, decodeCursor, idOnlySchema, paginate } from "./_helpers.js";
import { confirmDestructive } from "../elicit.js";
import { McpToolError } from "../errors.js";

// Default elicitation threshold for create_checkout_session — Rs 5,000 in
// paisa. Below this we skip the confirm modal (still scoped + audited).
// Phase 3 will move this to a per-token setting.
const ELICIT_THRESHOLD_PAISA = 500_000;

type PaymentsListResponse = {
  data: unknown[];
  meta: { total: number; limit: number; offset: number };
};

export const list_payments: ToolDefinition = {
  name: "list_payments",
  description:
    "List payments for the API key's project. Most recent first. Use cursor to page. Each payment has id, amount (paisa), currency, provider, status, customer info, and timestamps.",
  inputSchema: cursorAndLimitSchema,
  annotations: { readOnlyHint: true, title: "List payments" },
  requiredScopes: ["payments:read"],
  async handler(args, ctx) {
    const a = args as { cursor?: string; limit?: number };
    const limit = clampLimit(a.limit);
    const { offset } = decodeCursor(a.cursor);
    const raw = await ctx.api.get<PaymentsListResponse>("/v1/payments", {
      query: { limit, offset },
    });
    return paginate(raw, limit, offset);
  },
};

export const get_payment: ToolDefinition = {
  name: "get_payment",
  description:
    "Fetch a single payment by id. Returns full payment record including provider reference, amount, status, customer details, and metadata.",
  inputSchema: idOnlySchema("payment_id", "PayBridgeNP payment id (e.g., pay_abc123)."),
  annotations: { readOnlyHint: true, title: "Get payment" },
  requiredScopes: ["payments:read"],
  async handler(args, ctx) {
    const { payment_id } = args as { payment_id: string };
    if (!payment_id) throw new Error("payment_id is required");
    return ctx.api.get(`/v1/payments/${encodeURIComponent(payment_id)}`);
  },
};

export const create_checkout_session: ToolDefinition = {
  name: "create_checkout_session",
  description:
    "Create a hosted checkout session and return its checkout_url. Amount is in PAISA (e.g., 50000 = Rs 500). Customer is redirected to PayBridge to pick eSewa/Khalti/ConnectIPS and pay. Asks for confirmation when amount is large (default >= Rs 5,000).",
  inputSchema: {
    type: "object",
    properties: {
      amount: {
        type: "integer",
        minimum: 1,
        description: "Amount in paisa (1/100 of NPR).",
      },
      currency: {
        type: "string",
        default: "NPR",
        description: "ISO currency code. Currently only NPR is supported.",
      },
      provider: {
        type: "string",
        enum: ["esewa", "khalti", "connectips"],
        description: "Lock the session to a single provider. Omit to let the customer pick.",
      },
      return_url: {
        type: "string",
        format: "uri",
        description: "Where the customer is redirected after a successful payment.",
      },
      cancel_url: {
        type: "string",
        format: "uri",
        description: "Where the customer is redirected if they cancel.",
      },
      description: {
        type: "string",
        description: "Short description of what is being purchased (shown on the hosted page).",
      },
      customer: {
        type: "object",
        description: "Optional customer details to pre-fill on the hosted page.",
        properties: {
          name: { type: "string" },
          email: { type: "string", format: "email" },
          phone: { type: "string" },
        },
        additionalProperties: false,
      },
      metadata: {
        type: "object",
        description: "Free-form key/value pairs returned in the webhook + visible in the dashboard.",
        additionalProperties: true,
      },
      idempotency_key: {
        type: "string",
        description: "Optional Idempotency-Key — safe-retry the same operation without creating duplicates.",
      },
    },
    required: ["amount", "return_url", "cancel_url"],
    additionalProperties: false,
  },
  annotations: { destructiveHint: true, idempotentHint: true, title: "Create checkout session" },
  requiredScopes: ["payments:write"],
  async handler(args, ctx) {
    const a = args as {
      amount: number;
      currency?: string;
      provider?: "esewa" | "khalti" | "connectips";
      return_url: string;
      cancel_url: string;
      description?: string;
      customer?: { name?: string; email?: string; phone?: string };
      metadata?: Record<string, unknown>;
      idempotency_key?: string;
    };

    if (!Number.isInteger(a.amount) || a.amount <= 0) {
      throw new McpToolError("invalid_request", "amount must be a positive integer (paisa)", 400);
    }

    if (a.amount >= ELICIT_THRESHOLD_PAISA) {
      const ok = await confirmDestructive(ctx.elicit, {
        message: `Create a checkout session for ${a.currency ?? "NPR"} ${(a.amount / 100).toFixed(2)}?`,
        summary: {
          amount: `${a.currency ?? "NPR"} ${(a.amount / 100).toFixed(2)}`,
          provider: a.provider ?? "(customer picks)",
          customer: a.customer?.email ?? a.customer?.name ?? "(none)",
          description: a.description ?? "(none)",
        },
      });
      if (!ok) {
        throw new McpToolError("user_cancelled", "Checkout session cancelled by user.", 0);
      }
    }

    return ctx.api.post("/v1/checkout", {
      body: {
        amount: a.amount,
        currency: a.currency ?? "NPR",
        provider: a.provider,
        returnUrl: a.return_url,
        cancelUrl: a.cancel_url,
        description: a.description,
        customer: a.customer,
        metadata: a.metadata,
      },
      idempotencyKey: a.idempotency_key,
    });
  },
};
