import type { ToolDefinition } from "../types.js";

export const get_account: ToolDefinition = {
  name: "get_account",
  description:
    "Get info about the merchant account, project, and API key the assistant is currently authenticated as. Useful at the start of a session so the agent knows whose account it's operating on, and what scopes / spend cap / expiry are in effect.",
  inputSchema: { type: "object", properties: {}, additionalProperties: false },
  annotations: { readOnlyHint: true, title: "Get account" },
  requiredScopes: ["account:read"],
  async handler(_args, ctx) {
    return ctx.api.get("/v1/account");
  },
};
