// Tool registry. Phase 2 ships read + write tools for every endpoint
// available under /v1/* with API-key auth. Tools that require dashboard
// JWT routes (sessions list, payment links, analytics, audit, search,
// webhook test+deliveries CRUD with auth) land in a follow-up phase
// after their /v1/* equivalents are added in apps/api.

import type { ToolDefinition } from "../types.js";

import { list_payments, get_payment, create_checkout_session } from "./payments.js";
import { list_refunds, get_refund, create_refund } from "./refunds.js";
import {
  list_webhook_endpoints,
  list_webhook_deliveries,
  create_webhook_endpoint,
  update_webhook_endpoint,
  delete_webhook_endpoint,
} from "./webhooks.js";
import {
  list_plans,
  get_plan,
  create_plan,
  update_plan,
  list_customers,
  get_customer,
  create_customer,
  update_customer,
  list_subscriptions,
  get_subscription,
  create_subscription,
  pause_subscription,
  resume_subscription,
  cancel_subscription,
  change_subscription_plan,
  list_invoices,
  get_invoice,
} from "./billing.js";
import { list_checkout_sessions, get_checkout_session } from "./sessions.js";
import { list_payment_links, get_payment_link } from "./links.js";
import { get_analytics_overview } from "./analytics.js";
import { get_account } from "./account.js";

const READ_TOOLS: ToolDefinition[] = [
  get_account,
  list_payments,
  get_payment,
  list_refunds,
  get_refund,
  list_checkout_sessions,
  get_checkout_session,
  list_payment_links,
  get_payment_link,
  list_webhook_endpoints,
  list_webhook_deliveries,
  list_plans,
  get_plan,
  list_customers,
  get_customer,
  list_subscriptions,
  get_subscription,
  list_invoices,
  get_invoice,
  get_analytics_overview,
];

const WRITE_TOOLS: ToolDefinition[] = [
  create_checkout_session,
  create_refund,
  create_webhook_endpoint,
  update_webhook_endpoint,
  delete_webhook_endpoint,
  create_plan,
  update_plan,
  create_customer,
  update_customer,
  create_subscription,
  pause_subscription,
  resume_subscription,
  cancel_subscription,
  change_subscription_plan,
];

export const TOOLS: ReadonlyArray<ToolDefinition> = [...READ_TOOLS, ...WRITE_TOOLS];

export const TOOL_MAP: ReadonlyMap<string, ToolDefinition> = new Map(
  TOOLS.map((t) => [t.name, t] as const),
);

export function getTool(name: string): ToolDefinition | undefined {
  return TOOL_MAP.get(name);
}
