export type McpErrorCode =
  | "unauthorized"
  | "forbidden"
  | "insufficient_scope"
  | "not_found"
  | "invalid_request"
  | "rate_limited"
  | "over_spend_cap"
  | "elicitation_unsupported"
  | "user_cancelled"
  | "upstream_error"
  | "connection_error";

export class McpToolError extends Error {
  readonly code: McpErrorCode;
  readonly statusCode: number;
  readonly raw: Record<string, unknown> | null;

  constructor(
    code: McpErrorCode,
    message: string,
    statusCode = 500,
    raw: Record<string, unknown> | null = null,
  ) {
    super(message);
    this.name = "McpToolError";
    this.code = code;
    this.statusCode = statusCode;
    this.raw = raw;
    Object.setPrototypeOf(this, new.target.prototype);
  }
}

export function fromUpstream(
  status: number,
  body: Record<string, unknown> | null,
): McpToolError {
  const message =
    typeof body?.error === "string"
      ? body.error
      : typeof body?.message === "string"
        ? body.message
        : `HTTP ${status}`;

  switch (status) {
    case 401:
      return new McpToolError("unauthorized", message, 401, body);
    case 403:
      return new McpToolError("forbidden", message, 403, body);
    case 404:
      return new McpToolError("not_found", message, 404, body);
    case 400:
    case 422:
      return new McpToolError("invalid_request", message, status, body);
    case 429:
      return new McpToolError("rate_limited", message, 429, body);
    default:
      return new McpToolError("upstream_error", message, status, body);
  }
}
