import type { ToolDefinition } from "../types.js";
import { clampLimit, cursorAndLimitSchema, decodeCursor, idOnlySchema, paginate } from "./_helpers.js";

type ListResp = { data: unknown[]; meta?: { total?: number; limit?: number; offset?: number } };

export const list_payment_links: ToolDefinition = {
  name: "list_payment_links",
  description:
    "List payment links for the API key's project. Payment links are shareable URLs (no code integration needed) that customers open to pay. Each link has title, amount or amount range, active state, used count, expiry.",
  inputSchema: {
    type: "object",
    properties: {
      cursor: cursorAndLimitSchema.properties.cursor,
      limit: cursorAndLimitSchema.properties.limit,
      active: {
        type: "boolean",
        description: "Filter by active=true (live, accepting payments) or active=false (paused/cancelled).",
      },
    },
    additionalProperties: false,
  },
  annotations: { readOnlyHint: true, title: "List payment links" },
  requiredScopes: ["links:read"],
  async handler(args, ctx) {
    const a = args as { cursor?: string; limit?: number; active?: boolean };
    const limit = clampLimit(a.limit);
    const { offset } = decodeCursor(a.cursor);
    const raw = await ctx.api.get<ListResp>("/v1/payment-links", {
      query: { limit, offset, active: a.active === undefined ? undefined : String(a.active) },
    });
    return paginate(raw, limit, offset);
  },
};

export const get_payment_link: ToolDefinition = {
  name: "get_payment_link",
  description:
    "Fetch a single payment link by id, including its usage stats (views, used_count, conversion_rate).",
  inputSchema: idOnlySchema("link_id", "Payment link id (e.g., lnk_abc123)."),
  annotations: { readOnlyHint: true, title: "Get payment link" },
  requiredScopes: ["links:read"],
  async handler(args, ctx) {
    const { link_id } = args as { link_id: string };
    if (!link_id) throw new Error("link_id is required");
    return ctx.api.get(`/v1/payment-links/${encodeURIComponent(link_id)}`);
  },
};
