// Defends against three things on data flowing back to the model:
//   1. Secrets accidentally returned by upstream (sk_, pk_, whsec_).
//   2. PII that should be hidden unless the token has `pii:read`.
//   3. Prompt-injection payloads stuffed into user-controlled fields
//      (customer name, metadata, payment description).
//
// We do NOT try to "detect" prompt injection — that's unsolved. We mark
// any merchant-controlled free text as untrusted with sentinel fences so
// the model treats it as data, not instruction.

const SECRET_PATTERNS: Array<[RegExp, string]> = [
  [/\bsk_(live|test)_[A-Za-z0-9]{16,}\b/g, "[REDACTED:secret_key]"],
  [/\bpk_(live|test)_[A-Za-z0-9]{16,}\b/g, "[REDACTED:publishable_key]"],
  [/\bwhsec_[A-Za-z0-9]{16,}\b/g, "[REDACTED:webhook_secret]"],
  [/\bBearer\s+[A-Za-z0-9._\-]{20,}\b/gi, "[REDACTED:bearer_token]"],
];

const ZERO_WIDTH = /[\u200B-\u200F\u202A-\u202E\u2060-\u2064\uFEFF]/g;

const UNTRUSTED_FIELDS = new Set([
  "customer_name",
  "customer_email",
  "customer_phone",
  "description",
  "title",
  "notes",
  "metadata",
  "reference_id",
  "inactive_message",
]);

export function redactSecrets(input: string): string {
  let out = input;
  for (const [pattern, replacement] of SECRET_PATTERNS) {
    out = out.replace(pattern, replacement);
  }
  return out;
}

export function stripZeroWidth(input: string): string {
  return input.replace(ZERO_WIDTH, "");
}

export function fenceUntrusted(value: unknown): string {
  if (value == null) return "";
  const str = typeof value === "string" ? value : JSON.stringify(value);
  const cleaned = stripZeroWidth(str);
  return `<untrusted>${cleaned.replace(/<\/?untrusted>/g, "")}</untrusted>`;
}

export function hashEmail(email: string): string {
  const at = email.indexOf("@");
  if (at <= 0) return "[REDACTED]";
  const local = email.slice(0, at);
  const domain = email.slice(at + 1);
  const head = local.slice(0, Math.min(2, local.length));
  return `${head}***@${domain}`;
}

export function hashPhone(phone: string): string {
  const digits = phone.replace(/\D/g, "");
  if (digits.length < 4) return "[REDACTED]";
  return `***${digits.slice(-4)}`;
}

export type RedactOptions = {
  includePii: boolean;
};

// Walk a response object: redact secrets everywhere; mask PII when
// includePii is false; fence merchant-controlled fields as untrusted.
export function redactResponse<T>(value: T, opts: RedactOptions): T {
  return walk(value, opts) as T;
}

function walk(value: unknown, opts: RedactOptions, key?: string): unknown {
  if (value == null) return value;

  if (typeof value === "string") {
    let out = redactSecrets(stripZeroWidth(value));
    if (!opts.includePii) {
      if (key === "customerEmail" || key === "customer_email" || key === "email") {
        return hashEmail(out);
      }
      if (key === "customerPhone" || key === "customer_phone" || key === "phone") {
        return hashPhone(out);
      }
    }
    if (key && UNTRUSTED_FIELDS.has(snake(key))) {
      out = fenceUntrusted(out);
    }
    return out;
  }

  if (Array.isArray(value)) {
    return value.map((v) => walk(v, opts, key));
  }

  if (typeof value === "object") {
    const out: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
      out[k] = walk(v, opts, k);
    }
    return out;
  }

  return value;
}

function snake(s: string): string {
  return s.replace(/[A-Z]/g, (c) => `_${c.toLowerCase()}`).replace(/^_/, "");
}
