// Declarative scope model. Phase 1 ships with the model defined and
// per-tool annotations in place but enforcement is a no-op when the
// underlying api_keys row has scopes = NULL (back-compat for existing
// REST keys). Phase 2 turns enforcement on for MCP-kind keys.

export const ALL_SCOPES = [
  "account:read",
  "payments:read",
  "payments:write",
  "refunds:read",
  "refunds:write",
  "sessions:read",
  "links:read",
  "links:write",
  "webhooks:read",
  "webhooks:write",
  "billing:read",
  "billing:write",
  "analytics:read",
  "audit:read",
  "docs:read",
  "pii:read",
] as const;

export type Scope = (typeof ALL_SCOPES)[number];

export const DEFAULT_READ_SCOPES: ReadonlyArray<Scope> = [
  "account:read",
  "payments:read",
  "refunds:read",
  "sessions:read",
  "links:read",
  "webhooks:read",
  "billing:read",
  "analytics:read",
  "docs:read",
];

export type ScopeContext = {
  // null = legacy/REST key with no scope restrictions (full access).
  granted: ReadonlyArray<Scope> | null;
};

export function hasScope(ctx: ScopeContext, required: Scope): boolean {
  if (ctx.granted === null) return true;
  return ctx.granted.includes(required);
}

export function requireScope(ctx: ScopeContext, required: Scope): void {
  if (!hasScope(ctx, required)) {
    throw new ScopeError(required);
  }
}

export class ScopeError extends Error {
  readonly required: Scope;
  constructor(required: Scope) {
    super(`Missing required scope: ${required}`);
    this.name = "ScopeError";
    this.required = required;
    Object.setPrototypeOf(this, new.target.prototype);
  }
}
