import type { ToolDefinition } from "../types.js";

export const get_analytics_overview: ToolDefinition = {
  name: "get_analytics_overview",
  description:
    "Headline KPIs for the project over a rolling window (default 30 days, max 90). Returns: total payment count, success / failed counts, success rate, success volume in paisa, checkout funnel (sessions created → initiated → paid), per-provider breakdown.",
  inputSchema: {
    type: "object",
    properties: {
      days: {
        type: "integer",
        minimum: 1,
        maximum: 90,
        default: 30,
        description: "Rolling window in days (1–90).",
      },
    },
    additionalProperties: false,
  },
  annotations: { readOnlyHint: true, title: "Analytics overview" },
  requiredScopes: ["analytics:read"],
  async handler(args, ctx) {
    const a = args as { days?: number };
    return ctx.api.get("/v1/analytics/overview", { query: { days: a.days } });
  },
};
